const now = new Date();
const dateStr = now.toISOString().replace(/[:.]/g, '-').split('T')[0];
const timeStr = now.toISOString().replace(/[:.]/g, '-').split('T')[1].substring(0, 8);
const timestamp = `${dateStr}_${timeStr}`;

return [{
  json: {
    timestamp,
    date_str: dateStr,
    backup_filename: `puraestate_backup_${timestamp}.sql.gz`,
    backup_path: `/tmp/puraestate_backup_${timestamp}.sql.gz`,
    s3_key: `backups/postgresql/${dateStr}/puraestate_backup_${timestamp}.sql.gz`,
    s3_bucket: process.env.AWS_S3_BACKUP_BUCKET || 'puraestate-backups',
    db_host: process.env.DB_HOST || 'localhost',
    db_port: process.env.DB_PORT || '5432',
    db_name: process.env.DB_NAME || 'puraestate',
    db_user: process.env.DB_USER || 'puraestate_user'
  }
}];

const uploadOutput = $input.first().json.stdout || '';
const success = uploadOutput.includes('S3_UPLOAD_SUCCESS');

// Parse backup size
const sizeMatch = $('Run pg_dump').first().json.stdout?.match(/BACKUP_SIZE=(.+)/);
const backupSize = sizeMatch ? sizeMatch[1] : 'Unknown';

// Count existing backups (from ls output)
const backupLines = uploadOutput.split('\n').filter(l => l.includes('.sql.gz'));
const backupCount = backupLines.length;

// Calculate oldest backup to potentially clean up
const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);

return [{
  json: {
    success,
    backup_filename: $('Prepare Backup Config').first().json.backup_filename,
    s3_key: $('Prepare Backup Config').first().json.s3_key,
    s3_bucket: $('Prepare Backup Config').first().json.s3_bucket,
    backup_size: backupSize,
    backup_count: backupCount,
    backup_date: $('Prepare Backup Config').first().json.date_str,
    timestamp: new Date().toISOString()
  }
}];

